#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MAXLEN 100005

int min3(int x, int y, int z) {
    int m = x < y ? x : y;
    return m < z ? m : z;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        static char s[MAXLEN];
        static char w[MAXLEN];
        int a, b, k;
        scanf("%s", s);
        scanf("%s", w);
        scanf("%d %d %d", &a, &b, &k);
        int m = strlen(s);
        int n = strlen(w);
        // Ensure we iterate over the shorter string in the inner loop
        if (n > m) {
            // swap strings to keep n <= m
            char *tmp = s; s = w; w = tmp;
            int tm = m; m = n; n = tm;
        }
        int *prev = (int*)malloc((n + 1) * sizeof(int));
        int *cur  = (int*)malloc((n + 1) * sizeof(int));
        for (int j = 0; j <= n; ++j) prev[j] = j * a;
        for (int i = 1; i <= m; ++i) {
            cur[0] = i * a;
            for (int j = 1; j <= n; ++j) {
                if (s[i-1] == w[j-1])
                    cur[j] = prev[j-1];
                else
                    cur[j] = min3(prev[j] + a,        // delete
                                   cur[j-1] + a,      // insert
                                   prev[j-1] + b);    // substitute
            }
            int *tmp = prev; prev = cur; cur = tmp;
        }
        int ans = prev[n];
        if (ans <= k) printf("%d\n", ans);
        else printf("-1\n");
        free(prev);
        free(cur);
    }
    return 0;
}

