import java.io.*;
import java.util.*;

public class Main {
    private static int min3(int x, int y, int z) {
        return Math.min(x, Math.min(y, z));
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            String s = br.readLine().trim();
            String w = br.readLine().trim();
            StringTokenizer st = new StringTokenizer(br.readLine());
            int a = Integer.parseInt(st.nextToken());
            int b = Integer.parseInt(st.nextToken());
            int k = Integer.parseInt(st.nextToken());
            // ensure w is the shorter one
            if (w.length() > s.length()) { String tmp=s; s=w; w=tmp; }
            int m = s.length();
            int n = w.length();
            int[] prev = new int[n+1];
            int[] cur = new int[n+1];
            for (int j=0;j<=n;++j) prev[j]=j*a;
            for (int i=1;i<=m;++i) {
                cur[0]=i*a;
                for (int j=1;j<=n;++j) {
                    if (s.charAt(i-1)==w.charAt(j-1)) cur[j]=prev[j-1];
                    else cur[j]=min3(prev[j]+a, cur[j-1]+a, prev[j-1]+b);
                }
                int[] tmp = prev; prev = cur; cur = tmp;
            }
            int ans = prev[n];
            out.append(ans<=k?ans:-1).append('\n');
        }
        System.out.print(out.toString());
    }
}

