const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
function nextLine() { return lines[idx++]; }
const T = parseInt(nextLine(), 10);
let results = [];
for (let t = 0; t < T; ++t) {
    const sOrig = nextLine().trim();
    const wOrig = nextLine().trim();
    const [aStr, bStr, kStr] = nextLine().trim().split(' ');
    const a = parseInt(aStr, 10);
    const b = parseInt(bStr, 10);
    const k = parseInt(kStr, 10);
    // ensure w is the shorter string
    let s = sOrig, w = wOrig;
    if (w.length > s.length) { [s, w] = [w, s]; }
    const m = s.length, n = w.length;
    let prev = new Array(n + 1);
    let cur = new Array(n + 1);
    for (let j = 0; j <= n; ++j) prev[j] = j * a;
    for (let i = 1; i <= m; ++i) {
        cur[0] = i * a;
        const ch = s.charAt(i - 1);
        for (let j = 1; j <= n; ++j) {
            if (ch === w.charAt(j - 1)) {
                cur[j] = prev[j - 1];
            } else {
                const del = prev[j] + a;
                const ins = cur[j - 1] + a;
                const sub = prev[j - 1] + b;
                cur[j] = Math.min(del, ins, sub);
            }
        }
        const tmp = prev; prev = cur; cur = tmp;
    }
    const ans = prev[n];
    results.push(ans <= k ? String(ans) : '-1');
}
